function candidate(fn, capacity) {
  const max = capacity === undefined ? 1 : Math.max(0, Math.floor(capacity));
  const entries = [];

  return function(arg) {
    for (let i = 0; i < entries.length; i += 1) {
      if (entries[i].key === arg) {
        const hit = entries[i];
        if (i !== entries.length - 1) {
          entries.splice(i, 1);
          entries.push(hit);
        }
        return hit.value;
      }
    }

    const value = fn(arg);

    if (max > 0) {
      entries.push({ key: arg, value: value });
      if (entries.length > max) {
        entries.shift();
      }
    }

    return value;
  };
}
